#graphql
  mutation BulkOperationRunMutationOperationInProgress($mutation: String!, $path: String!) {
    bulkOperationRunMutation(mutation: $mutation, stagedUploadPath: $path) {
      bulkOperation {

  id
  status
  type
  errorCode
  createdAt
  completedAt
  objectCount
  rootObjectCount
  fileSize
  url
  partialDataUrl
  query

      }
      userErrors {
        field
        message
        code
      }
    }
  }

